    "privacy.nocollect.5": "Crash reports sent to our servers",
    "privacy.credentials.title": "Your Credentials",
    "privacy.credentials.desc": "When you log in to your Home Assistant instance via OAuth, the resulting access token is stored exclusively in the iOS Keychain on your device. It is never transmitted to any server other than your own Home Assistant instance.",
    "privacy.sharing.title": "Layout Sharing",
    "privacy.sharing.desc": "If you use the Pro layout sharing feature, an encrypted snapshot of your chosen entity layout is embedded in an invite link. This data is not stored on any HAHome server — the link itself carries the encrypted payload directly. Only people you explicitly share the link with can import your layout.",
    "privacy.thirdparty.title": "Third-Party Services",
    "privacy.thirdparty.desc": "HAHome does not integrate any third-party analytics, advertising, or crash-reporting SDKs. The only network communication the app performs is directly between your device and your Home Assistant server.",
    "privacy.iap.title": "In-App Purchases",
    "privacy.iap.desc": "HAHome Pro is purchased through Apple's App Store. Apple handles all payment processing. HAHome does not receive or store any payment or billing information.",
    "privacy.children.title": "Children's Privacy",
    "privacy.children.desc": "HAHome does not knowingly collect any information from children under 13. Because we collect no personal data from any user, the app is safe for all ages.",
    "privacy.changes.title": "Changes to This Policy",
