    "hero.badge": "Prossimamente sull'App Store",
    "hero.title": 'La tua casa intelligente,<br><span class="gradient">magnificamente sotto controllo.</span>',
    "hero.sub": "HAHome è l'app nativa Apple che il tuo Home Assistant merita. Controlla luci, clima, tapparelle, media, sicurezza e altro — con un design che si sente a casa.",
    "hero.cta_pro": "Pro — 4,99 €",
    "hero.cta_features": "Vedi funzionalità",

    "features.label": "Funzionalità",
    "features.title": "Tutto ciò di cui hai bisogno, niente di superfluo.",
    "features.subtitle": "Progettata da zero come app nativa Apple — veloce, intuitiva e sempre aggiornata.",
    "features.realtime.title": "Aggiornamenti in tempo reale",
    "features.realtime.desc": "La connessione WebSocket mantiene lo stato di ogni dispositivo in diretta. Attiva una luce e vedi la risposta istantaneamente — nessun polling, nessun ritardo.",
    "features.rooms.title": "Organizzazione per stanza",
    "features.rooms.desc": "Raggruppa le entità per stanza con nomi e sfondi personalizzati. Visualizza un riepilogo dei sensori a colpo d'occhio prima di aprire la stanza.",
    "features.energy.title": "Pannello energia",
    "features.energy.desc": "Visualizza solare, rete, batteria, gas e acqua in un diagramma di flusso energetico in tempo reale. Monitora il consumo orario con grafici eleganti.",
    "features.customise.title": "Personalizza tutto",
    "features.customise.desc": "Scegli tra 19 temi — inclusi Temi Adattivi che passano automaticamente tra varianti chiare e scure in base all'aspetto del sistema. Imposta sfondi unici per stanza, scegli icone personalizzate e regola i colori in base al tuo stile.",
    "features.secure.title": "Sicuro e Privato",
    "features.secure.desc": "Le credenziali sono archiviate nel Portachiavi iOS. OAuth con PKCE e il pinning dei certificati Trust-on-First-Use proteggono la tua connessione. Nessun server di terze parti.",
    "features.sharing.title": "Condivisione layout",
    "features.sharing.desc": "Condividi il layout della tua casa con fino a 9 persone tramite un link di invito crittografato. Scegli esattamente quali entità ogni persona può vedere.",
    "features.weather.title": "Meteo a colpo d'occhio",
    "features.weather.desc": "Un widget meteo nella barra degli strumenti mostra l'entità meteo del tuo Home Assistant proprio dove ti serve, senza uscire dall'app.",
    "features.platforms.title": "iPhone & Mac",
    "features.platforms.desc": "Un acquisto, due piattaforme. HAHome funziona nativamente su iOS e macOS con un'esperienza adattata a ogni dimensione di schermo.",
    "features.languages.title": "Multilingua",
    "features.languages.desc": "HAHome parla la tua lingua. Disponibile in inglese, olandese, francese, tedesco, spagnolo, italiano, portoghese, polacco e svedese.",

    "screenshots.label": "Screenshot",
    "screenshots.title": "Guardalo in azione.",
    "screenshots.subtitle": "Un'anteprima di ciò che ti aspetta.",

    // See It In Action
    "action.label": "Guardalo in azione",
    "action.title": "Guardalo in azione.",
    "action.subtitle": "Un'anteprima di ciò che ti aspetta.",
    "action.home.title": "Schermata principale",
    "action.home.desc": "Tutta la tua casa intelligente a colpo d'occhio — meteo, preferiti, telecamere in diretta e riquadri stanza con lo stato dei dispositivi.",
    "action.light.title": "Controllo luci",
    "action.light.desc": "Trascina il cursore della luminosità e scegli una temperatura colore. Controllo fluido e reattivo per ogni luce della tua casa.",
    "action.climate.title": "Controllo climatico",
    "action.climate.desc": "Un quadrante della temperatura interattivo con modalità HVAC, preimpostazione, velocità ventola e oscillazione — tutto in un'unica schermata.",
    "action.blinds.title": "Tapparelle e tende",
    "action.blinds.desc": "Imposta la posizione esatta con un cursore, oppure tocca Apri, Stop e Chiudi per un controllo rapido di tapparelle, persiane e tende.",
    "action.media.title": "Lettore multimediale",
    "action.media.desc": "Copertina album, manopola del volume circolare, controlli di riproduzione e selezione sorgente — un telecomando completo per TV e altoparlanti.",
    "action.fan.title": "Controllo ventilatore",
    "action.fan.desc": "Regola la velocità con un cursore, scegli una modalità preimpostata e attiva l'oscillazione — tutto il necessario per ventilatori e purificatori d'aria.",
    "action.alarm.title": "Pannello allarme",
    "action.alarm.desc": "Attiva e disattiva la sicurezza della casa con un tocco. Supporta le modalità Assente, Casa, Notte e Vacanza.",
    "action.person.title": "Tracciamento persone",
    "action.person.desc": "Visualizza dove si trovano i membri della famiglia su una mappa in tempo reale tramite Apple Maps — direttamente dalla schermata principale.",

    // Configuration
    "config.label": "Configurazione",
    "config.title": "Configura a modo tuo.",
    "config.subtitle": "Scegli le tue entità, seleziona un tema e regola ogni dettaglio prima di iniziare a controllare.",
    "config.entities.title": "Gestisci entità",
    "config.entities.desc": "Tocca una categoria per scegliere quali entità gestire. Luci, clima, interruttori, tapparelle, media, sicurezza, energia e automazioni — tutto in un unico posto.",
    "config.lights.title": "Seleziona luci",
